use std::collections::VecDeque;
use std::io::{self, Read, Seek, SeekFrom, Write};
use std::time::{Duration, Instant};

const SYNC_LENGTH: usize = 40;
const SYNCA_SEQ: [bool; SYNC_LENGTH] = [
    false, false, false, false, true, true, false, false, true, true, false, false, true, true,
    false, false, true, true, false, false, true, true, false, false, true, true, false, false,
    true, true, false, false, false, false, false, false, false, false, false, false,
];
const SYNCB_SEQ: [bool; SYNC_LENGTH] = [
    false, false, false, false, true, true, true, false, false, true, true, true, false, false,
    true, true, true, false, false, true, true, true, false, false, true, true, true, false, false,
    true, true, true, false, false, true, true, true, false, false, false,
];

