fn arg_value(name: &str, default: &str) -> String {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next().unwrap_or_else(|| default.to_string());
        }
    }
    default.to_string()
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let input_rate = arg_value("--input-rate", "11025").parse::<f32>()?;
    if (input_rate - 48000.0).abs() > 1.0 {
        return Err(format!(
            "noaa-apt-audio-frame expects 48000 Hz FM-demodulated mono PCM, got {} Hz",
            input_rate
        )
        .into());
    }
    let freq_hz = arg_value("--freq-hz", "137100000").parse::<u64>()?;
    let output = arg_value("--output", "noaa_apt.frame");
    let width = arg_value("--width", "2080").parse::<usize>()?;
    let max_lines = arg_value("--max-lines", "2400").parse::<usize>()?;
    let publish_lines = arg_value("--publish-lines", "4").parse::<usize>()?;
    let debug_lines_limit = arg_value("--debug-lines", "120").parse::<usize>()?;
    let publish_ms = arg_value("--publish-ms", "250").parse::<u64>()?;
    let source_id = arg_value("--source-id", "noaa_apt_live");
    let wav_output = arg_value("--wav-output", "");
    let high_sens = std::env::var("AEON_NOAA_HIGH_SENS")
        .map(|v| v != "0")
        .unwrap_or(true);

    let mut decoder = AptEnvelopeDecoder::new(width);
    let mut wav_tap = if wav_output.is_empty() {
        None
    } else {
        Some(WavTap::create(&wav_output, input_rate as u32)?)
    };
    let mut lines: VecDeque<Vec<u8>> = VecDeque::with_capacity(max_lines);
    let mut sync_scores: VecDeque<f32> = VecDeque::with_capacity(max_lines);
    let mut debug_lines: VecDeque<Vec<u8>> = VecDeque::with_capacity(debug_lines_limit);
    let mut debug_scores: VecDeque<f32> = VecDeque::with_capacity(debug_lines_limit);
    let mut last_publish = Instant::now();
    let mut last_status = Instant::now();
    let mut stdin = io::stdin().lock();
    let mut buf = [0u8; 16384];

    eprintln!(
        "[NOAA-APT] decoding PCM audio: input_rate={}Hz width={} freq={}Hz",
        input_rate, width, freq_hz
    );

    loop {
        let n = stdin.read(&mut buf)?;
        if n == 0 {
            break;
        }

        for chunk in buf[..n].chunks_exact(2) {
            let sample = i16::from_le_bytes([chunk[0], chunk[1]]) as f32 / 32768.0;
            if let Some(tap) = wav_tap.as_mut() {
                tap.write_sample(sample)?;
            }
            if let Some(decoded) = decoder.push_sample(sample) {
                if high_sens {
                    debug_lines.push_back(decoded.debug_line.clone());
                    debug_scores.push_back(decoded.sync_score * decoded.stability);
                    while debug_lines.len() > debug_lines_limit {
                        debug_lines.pop_front();
                        debug_scores.pop_front();
                    }
                }

                if decoded.accepted {
                    lines.push_back(decoded.line);
                    sync_scores.push_back(decoded.sync_score * decoded.stability);
                }
                while lines.len() > max_lines {
                    lines.pop_front();
                    sync_scores.pop_front();
                }

                if (decoded.accepted && lines.len().is_multiple_of(publish_lines))
                    || last_publish.elapsed() >= Duration::from_millis(publish_ms)
                {
                    if lines.is_empty() && high_sens && !debug_lines.is_empty() {
                        publish_debug_frame(
                            &output,
                            &source_id,
                            freq_hz,
                            width,
                            &debug_lines,
                            &debug_scores,
                            &decoder,
                        )?;
                    } else {
                        publish_frame(&output, &source_id, freq_hz, width, &lines, &sync_scores)?;
                    }
                    last_publish = Instant::now();
                }
            }
        }

        if last_status.elapsed() >= Duration::from_secs(2) {
            decoder.write_status(lines.len());
            if lines.is_empty() && high_sens && !debug_lines.is_empty() {
                publish_debug_frame(
                    &output,
                    &source_id,
                    freq_hz,
                    width,
                    &debug_lines,
                    &debug_scores,
                    &decoder,
                )?;
            } else if lines.is_empty() {
                publish_status_frame(&output, &source_id, freq_hz, width, &decoder)?;
            }
            last_status = Instant::now();
        }
    }

    if !lines.is_empty() {
        publish_frame(&output, &source_id, freq_hz, width, &lines, &sync_scores)?;
    }

    Ok(())
}

struct AptEnvelopeDecoder {
    width: usize,
    dc: f32,
    fir: FirFilter,
    resample_phase: usize,
    raw_line: Vec<f32>,
    syncer: StreamingAptSyncer,
    synced_line: Vec<f32>,
    seen_stream_sync: bool,
    sync_offsets: VecDeque<usize>,
    complete_lines: u64,
    accepted_lines: u64,
    rejected_lines: u64,
    last_sync_score: f32,
    last_sync_stability: f32,
    last_sync_offset: usize,
    rms_slow: f32,
}

impl AptEnvelopeDecoder {
    fn new(width: usize) -> Self {
        Self {
            width,
            dc: 0.0,
            fir: FirFilter::new(&LOWPASS_COEFFS),
            resample_phase: 0,
            raw_line: Vec::with_capacity(width),
            syncer: StreamingAptSyncer::new(),
            synced_line: Vec::with_capacity(width),
            seen_stream_sync: false,
            sync_offsets: VecDeque::with_capacity(32),
            complete_lines: 0,
            accepted_lines: 0,
            rejected_lines: 0,
            last_sync_score: 0.0,
            last_sync_stability: 0.0,
            last_sync_offset: 0,
            rms_slow: 0.0,
        }
    }

    fn push_sample(&mut self, sample: f32) -> Option<DecodedLine> {
        self.rms_slow = self.rms_slow * 0.999 + (sample * sample) * 0.001;
        self.dc = self.dc * 0.999 + sample * 0.001;
        let demod = (sample - self.dc).abs();
        let filtered = self.fir.process(demod);

        self.resample_phase += 13;
        if self.resample_phase < 150 {
            return None;
        }
        self.resample_phase -= 150;

        let pixel = filtered.max(0.0);
        if let Some(sync_sample) = self.syncer.push(pixel) {
            if let Some(decoded) = self.push_synced_sample(sync_sample) {
                return Some(decoded);
            }
        }

        self.raw_line.push(pixel);

        if self.raw_line.len() >= self.width {
            self.complete_lines = self.complete_lines.saturating_add(1);
            let mut raw_complete = Vec::with_capacity(self.width);
            std::mem::swap(&mut raw_complete, &mut self.raw_line);
            let mut complete = normalize_scanline(&raw_complete);
            let (offset, sync_score) = best_sync_offset(&complete);
            self.sync_offsets.push_back(offset);
            while self.sync_offsets.len() > 32 {
                self.sync_offsets.pop_front();
            }
            let stability = sync_stability(&self.sync_offsets, self.width);
            self.last_sync_score = sync_score;
            self.last_sync_stability = stability;
            self.last_sync_offset = offset;
            if sync_score >= 0.18 && stability >= 0.65 {
                self.accepted_lines = self.accepted_lines.saturating_add(1);
                complete.rotate_left(offset);
                return Some(DecodedLine {
                    debug_line: complete.clone(),
                    line: complete,
                    sync_score,
                    stability,
                    accepted: true,
                });
            }
            let mut debug_line = complete.clone();
            debug_line.rotate_left(offset);
            self.rejected_lines = self.rejected_lines.saturating_add(1);
            return Some(DecodedLine {
                debug_line,
                line: complete,
                sync_score,
                stability,
                accepted: false,
            });
        }

        None
    }

    fn push_synced_sample(&mut self, sample: SyncedSample) -> Option<DecodedLine> {
        match sample {
            SyncedSample::Sample(value) => {
                if self.seen_stream_sync {
                    self.synced_line.push(value);
                    if self.synced_line.len() >= self.width {
                        return self.finish_stream_line(false);
                    }
                }
            }
            SyncedSample::SyncA(value) => {
                if self.seen_stream_sync && self.synced_line.len() > self.width / 2 {
                    if let Some(decoded) = self.finish_stream_line(true) {
                        self.synced_line.clear();
                        self.synced_line.push(value);
                        return Some(decoded);
                    }
                }
                self.seen_stream_sync = true;
                self.synced_line.clear();
                self.synced_line.push(value);
            }
            SyncedSample::SyncB(value) => {
                if self.seen_stream_sync {
                    while self.synced_line.len() < self.width / 2 {
                        let fill = self.synced_line.last().copied().unwrap_or(value);
                        self.synced_line.push(fill);
                    }
                    if self.synced_line.len() > self.width / 2 {
                        self.synced_line.truncate(self.width / 2);
                    }
                    self.synced_line.push(value);
                }
            }
        }
        None
    }

    fn finish_stream_line(&mut self, accepted: bool) -> Option<DecodedLine> {
        if self.synced_line.is_empty() {
            return None;
        }
        while self.synced_line.len() < self.width {
            let fill = self.synced_line.last().copied().unwrap_or(0.0);
            self.synced_line.push(fill);
        }
        if self.synced_line.len() > self.width {
            self.synced_line.truncate(self.width);
        }
        self.complete_lines = self.complete_lines.saturating_add(1);
        let complete = normalize_scanline(&self.synced_line);
        let sync_score = apt_frame_sync_score(&complete, 0);
        self.last_sync_score = sync_score;
        self.last_sync_stability = 1.0;
        self.last_sync_offset = 0;
        self.synced_line.clear();
        if accepted || sync_score >= 0.55 {
            self.accepted_lines = self.accepted_lines.saturating_add(1);
            Some(DecodedLine {
                debug_line: complete.clone(),
                line: complete,
                sync_score,
                stability: 1.0,
                accepted: true,
            })
        } else {
            self.rejected_lines = self.rejected_lines.saturating_add(1);
            Some(DecodedLine {
                debug_line: complete.clone(),
                line: complete,
                sync_score,
                stability: 1.0,
                accepted: false,
            })
        }
    }

    fn write_status(&self, published_lines: usize) {
        let status = format!(
            "[NOAA-APT] sync search: audio_rms={:.4} complete={} accepted={} rejected={} published={} sync={:.3} stability={:.3} offset={}",
            self.rms_slow.sqrt(),
            self.complete_lines,
            self.accepted_lines,
            self.rejected_lines,
            published_lines,
            self.last_sync_score,
            self.last_sync_stability,
            self.last_sync_offset
        );
        eprintln!("{}", status);
        let _ = std::fs::OpenOptions::new()
            .append(true)
            .create(true)
            .open("gateway.log")
            .and_then(|mut f| writeln!(f, "{}", status));
    }
}

struct FirFilter {
    coeffs: &'static [f32],
    state: Vec<f32>,
    pos: usize,
}

impl FirFilter {
    fn new(coeffs: &'static [f32]) -> Self {
        Self {
            coeffs,
            state: vec![0.0; coeffs.len()],
            pos: 0,
        }
    }

    fn process(&mut self, input: f32) -> f32 {
        self.pos = (self.pos + 1) % self.coeffs.len();
        self.state[self.pos] = input;
        let mut result = 0.0;
        for i in 0..self.coeffs.len() {
            let pos = (self.pos + self.coeffs.len() - i) % self.coeffs.len();
            result += self.state[pos] * self.coeffs[i];
        }
        result
    }
}

struct WavTap {
    file: std::fs::File,
    sample_rate: u32,
    data_bytes: u32,
}

impl WavTap {
    fn create(path: &str, sample_rate: u32) -> io::Result<Self> {
        let mut file = std::fs::File::create(path)?;
        write_wav_header(&mut file, sample_rate, 0)?;
        Ok(Self {
            file,
            sample_rate,
            data_bytes: 0,
        })
    }

    fn write_sample(&mut self, sample: f32) -> io::Result<()> {
        self.file.write_all(&sample.to_le_bytes())?;
        self.data_bytes = self.data_bytes.saturating_add(4);
        if self.data_bytes.is_multiple_of(self.sample_rate * 4) {
            self.refresh_header()?;
        }
        Ok(())
    }

    fn refresh_header(&mut self) -> io::Result<()> {
        let end = self.file.stream_position()?;
        self.file.seek(SeekFrom::Start(0))?;
        write_wav_header(&mut self.file, self.sample_rate, self.data_bytes)?;
        self.file.seek(SeekFrom::Start(end))?;
        self.file.flush()
    }

    fn finalize(&mut self) -> io::Result<()> {
        self.refresh_header()
    }
}

impl Drop for WavTap {
    fn drop(&mut self) {
        let _ = self.finalize();
    }
}

fn write_wav_header(file: &mut std::fs::File, sample_rate: u32, data_bytes: u32) -> io::Result<()> {
    let riff_size = 36u32.saturating_add(data_bytes);
    let byte_rate = sample_rate * 4;
    file.write_all(b"RIFF")?;
    file.write_all(&riff_size.to_le_bytes())?;
    file.write_all(b"WAVE")?;
    file.write_all(b"fmt ")?;
    file.write_all(&16u32.to_le_bytes())?;
    file.write_all(&3u16.to_le_bytes())?;
    file.write_all(&1u16.to_le_bytes())?;
    file.write_all(&sample_rate.to_le_bytes())?;
    file.write_all(&byte_rate.to_le_bytes())?;
    file.write_all(&4u16.to_le_bytes())?;
    file.write_all(&32u16.to_le_bytes())?;
    file.write_all(b"data")?;
    file.write_all(&data_bytes.to_le_bytes())?;
    Ok(())
}

enum SyncedSample {
    Sample(f32),
    SyncA(f32),
    SyncB(f32),
}

struct StreamingAptSyncer {
    state: [f32; SYNC_LENGTH],
    pos: usize,
    filled: usize,
    avg_level: f32,
}

impl StreamingAptSyncer {
    fn new() -> Self {
        Self {
            state: [0.0; SYNC_LENGTH],
            pos: 0,
            filled: 0,
            avg_level: 0.5,
        }
    }

    fn push(&mut self, sample: f32) -> Option<SyncedSample> {
        if self.filled < SYNC_LENGTH {
            self.state[self.pos] = sample;
            self.pos = (self.pos + 1) % SYNC_LENGTH;
            self.filled += 1;
            self.avg_level = 0.25 * sample + self.avg_level * 0.75;
            return None;
        }

        let (is_a, is_b) = self.is_marker();
        let outgoing = self.state[self.pos];
        self.state[self.pos] = sample;
        self.avg_level = 0.25 * sample + self.avg_level * 0.75;
        self.pos = (self.pos + 1) % SYNC_LENGTH;

        if is_a {
            Some(SyncedSample::SyncA(outgoing))
        } else if is_b {
            Some(SyncedSample::SyncB(outgoing))
        } else {
            Some(SyncedSample::Sample(outgoing))
        }
    }

    fn is_marker(&self) -> (bool, bool) {
        let mut count_a = 0usize;
        let mut count_b = 0usize;
        for i in 0..SYNC_LENGTH {
            let sync_pos = (self.pos + i) % SYNC_LENGTH;
            let high = self.state[sync_pos] / (self.avg_level * 2.0).max(0.000001) > 0.5;
            if high == SYNCA_SEQ[i] {
                count_a += 1;
            }
            if high == SYNCB_SEQ[i] {
                count_b += 1;
            }
        }
        (count_a > 35, count_b > 35)
    }
}

struct DecodedLine {
    debug_line: Vec<u8>,
    line: Vec<u8>,
    sync_score: f32,
    stability: f32,
    accepted: bool,
}

fn normalize_scanline(raw: &[f32]) -> Vec<u8> {
    let mut max_level = 0.0f32;
    for &sample in raw {
        max_level = max_level.max(sample);
    }
    let scale = if max_level > 0.0000001 {
        255.0 / max_level
    } else {
        0.0
    };
    raw.iter()
        .map(|sample| (sample * scale).clamp(0.0, 255.0) as u8)
        .collect()
}

fn best_sync_offset(line: &[u8]) -> (usize, f32) {
    if line.len() < 2080 {
        return (0, 0.0);
    }
    let mut best_offset = 0usize;
    let mut best_score = -1.0f32;
    for offset in 0..line.len() {
        let score = apt_frame_sync_score(line, offset);
        if score > best_score {
            best_score = score;
            best_offset = offset;
        }
    }
    (best_offset, best_score.clamp(0.0, 1.0))
}

fn apt_frame_sync_score(line: &[u8], offset: usize) -> f32 {
    // NOAA APT line geometry from the frame-format diagram:
    // Sync A starts at the line origin and Sync B starts half a line later.
    // Score both locations together so random high-contrast texture is much
    // less likely to look "locked".
    let sync_a = marker_seq_score(line, offset, &SYNCA_SEQ);
    let sync_b = marker_seq_score(line, offset + 1040, &SYNCB_SEQ);

    let space_a = quiet_region_score(line, offset + 39, 47);
    let space_b = quiet_region_score(line, offset + 1079, 47);
    let telemetry_a = region_contrast(line, offset + 995, 45);
    let telemetry_b = region_contrast(line, offset + 2035, 45);

    (sync_a * 0.38
        + sync_b * 0.38
        + space_a * 0.08
        + space_b * 0.08
        + telemetry_a * 0.04
        + telemetry_b * 0.04)
        .clamp(0.0, 1.0)
}

fn marker_seq_score(line: &[u8], start: usize, seq: &[bool; SYNC_LENGTH]) -> f32 {
    let avg = line.iter().map(|&v| v as f32).sum::<f32>() / line.len().max(1) as f32;
    let threshold = (avg * 1.25).clamp(8.0, 220.0);
    let mut matches = 0usize;
    for i in 0..SYNC_LENGTH {
        let high = line[(start + i) % line.len()] as f32 > threshold;
        if high == seq[i] {
            matches += 1;
        }
    }
    matches as f32 / SYNC_LENGTH as f32
}

fn quiet_region_score(line: &[u8], start: usize, len: usize) -> f32 {
    let values = (0..len).map(|i| line[(start + i) % line.len()] as f32 / 255.0);
    let mean = values.clone().sum::<f32>() / len.max(1) as f32;
    let variance = values
        .map(|v| {
            let d = v - mean;
            d * d
        })
        .sum::<f32>()
        / len.max(1) as f32;
    (1.0 - variance.sqrt() * 6.0).clamp(0.0, 1.0)
}

fn region_contrast(line: &[u8], start: usize, len: usize) -> f32 {
    let mut min_v = 1.0f32;
    let mut max_v = 0.0f32;
    for i in 0..len {
        let v = line[(start + i) % line.len()] as f32 / 255.0;
        min_v = min_v.min(v);
        max_v = max_v.max(v);
    }
    (max_v - min_v).clamp(0.0, 1.0)
}

fn sync_stability(offsets: &VecDeque<usize>, width: usize) -> f32 {
    if offsets.len() < 8 || width == 0 {
        return 0.0;
    }
    let newest = *offsets.back().unwrap_or(&0);
    let close = offsets
        .iter()
        .filter(|&&offset| {
            let d = offset.abs_diff(newest);
            d.min(width.saturating_sub(d)) <= 12
        })
        .count();
    close as f32 / offsets.len() as f32
}

fn publish_frame(
    output: &str,
    source_id: &str,
    freq_hz: u64,
    width: usize,
    lines: &VecDeque<Vec<u8>>,
    sync_scores: &VecDeque<f32>,
) -> Result<(), Box<dyn std::error::Error>> {
    let height = lines.len();
    let mut data = Vec::with_capacity(width * height);
    for line in lines {
        data.extend_from_slice(line);
    }

    let mut frame = PleromaticFrame::noaa_apt_scanlines(
        source_id.to_string(),
        width,
        height,
        data,
        Some(freq_hz),
    );
    let mean_quality = if sync_scores.is_empty() {
        0.0
    } else {
        sync_scores.iter().copied().sum::<f32>() / sync_scores.len() as f32
    };
    let sync_status = if height >= 40 && mean_quality >= 0.12 {
        "candidate"
    } else {
        "searching"
    };
    frame
        .attributes
        .insert("apt_sync".to_string(), sync_status.to_string());
    frame
        .attributes
        .insert("apt_quality".to_string(), format!("{:.5}", mean_quality));
    frame
        .attributes
        .insert("apt_stability".to_string(), format!("{:.5}", mean_quality));
    let bytes = bincode::serialize(&frame)?;
    std::fs::write(output, bytes)?;

    let _ = std::fs::OpenOptions::new()
        .append(true)
        .create(true)
        .open("gateway.log")
        .and_then(|mut f| writeln!(f, "[NOAA-APT] decoded live scanlines: {}", height));

    Ok(())
}

fn publish_status_frame(
    output: &str,
    source_id: &str,
    freq_hz: u64,
    width: usize,
    decoder: &AptEnvelopeDecoder,
) -> Result<(), Box<dyn std::error::Error>> {
    let mut data = vec![0u8; width];
    let marker = (decoder.last_sync_offset % width).min(width.saturating_sub(1));
    if width > 0 {
        data[marker] = 255;
    }
    let mut frame =
        PleromaticFrame::noaa_apt_scanlines(source_id.to_string(), width, 1, data, Some(freq_hz));
    let audio_rms = decoder.rms_slow.sqrt();
    let signal_state = if audio_rms < 0.002 {
        "silent"
    } else {
        "signal_no_sync"
    };
    frame
        .attributes
        .insert("apt_sync".to_string(), signal_state.to_string());
    frame.attributes.insert(
        "apt_quality".to_string(),
        format!(
            "{:.5}",
            decoder.last_sync_score * decoder.last_sync_stability
        ),
    );
    frame.attributes.insert(
        "apt_stability".to_string(),
        format!("{:.5}", decoder.last_sync_stability),
    );
    frame
        .attributes
        .insert("audio_rms".to_string(), format!("{:.5}", audio_rms));
    frame.attributes.insert(
        "apt_rejected_lines".to_string(),
        decoder.rejected_lines.to_string(),
    );
    let bytes = bincode::serialize(&frame)?;
    std::fs::write(output, bytes)?;
    Ok(())
}

fn publish_debug_frame(
    output: &str,
    source_id: &str,
    freq_hz: u64,
    width: usize,
    lines: &VecDeque<Vec<u8>>,
    scores: &VecDeque<f32>,
    decoder: &AptEnvelopeDecoder,
) -> Result<(), Box<dyn std::error::Error>> {
    let height = lines.len();
    let mut data = Vec::with_capacity(width * height);
    for line in lines {
        data.extend_from_slice(line);
    }
    let mut frame = PleromaticFrame::noaa_apt_scanlines(
        source_id.to_string(),
        width,
        height,
        data,
        Some(freq_hz),
    );
    let mean_score = if scores.is_empty() {
        0.0
    } else {
        scores.iter().copied().sum::<f32>() / scores.len() as f32
    };
    frame
        .attributes
        .insert("apt_sync".to_string(), "unstable_high_sens".to_string());
    frame
        .attributes
        .insert("apt_quality".to_string(), format!("{:.5}", mean_score));
    frame.attributes.insert(
        "apt_stability".to_string(),
        format!("{:.5}", decoder.last_sync_stability),
    );
    frame.attributes.insert(
        "audio_rms".to_string(),
        format!("{:.5}", decoder.rms_slow.sqrt()),
    );
    frame.attributes.insert(
        "apt_rejected_lines".to_string(),
        decoder.rejected_lines.to_string(),
    );
    frame.attributes.insert(
        "apt_sync_offset".to_string(),
        decoder.last_sync_offset.to_string(),
    );
    let bytes = bincode::serialize(&frame)?;
    std::fs::write(output, bytes)?;
    Ok(())
}
